INSERT INTO public.bdd_scenarios (scenario_id, feature_area, feature_area_number, title, gherkin, status, test_type) VALUES
('BURP-INJECT-001', 'Security', 21, 'SQL injection and XSS payloads rejected by edge functions', 'Given an attacker sends SQLi or XSS payloads to edge functions\nWhen the request reaches the server\nThen it is rejected with 400/403 before reaching the database', 'implemented', 'manual'),
('BURP-AUTHZ-001', 'Security', 21, 'Unauthenticated requests to protected endpoints return 401', 'Given an unauthenticated request to a protected edge function\nWhen the function processes it\nThen it returns 401 Authentication required', 'implemented', 'manual'),
('BURP-IDOR-001', 'Security', 21, 'Roster IDOR via email spoofing prevented', 'Given a user changes their profile email to another member email\nWhen the prevent_email_change trigger fires\nThen the email change is reverted for authenticated users', 'implemented', 'unit'),
('BURP-METHOD-001', 'Security', 21, 'HTTP method enforcement on confirm-admin-role', 'Given a POST request to confirm-admin-role\nWhen the function checks the method\nThen it returns 405 Method Not Allowed', 'implemented', 'manual'),
('BURP-PATH-001', 'Security', 21, 'Path traversal tokens rejected by regex validation', 'Given a token containing path traversal sequences like ../../\nWhen confirm-admin-role validates it\nThen it returns 400 Invalid or missing token', 'implemented', 'manual'),
('BURP-SSRF-001', 'Security', 21, 'SSRF attempts to internal metadata endpoints blocked', 'Given a request with a 169.254.x.x URL to scrape-knowledge\nWhen the function checks authentication\nThen it returns 401 before any server-side request is made', 'implemented', 'manual');